firmware_template.source:
#include "dc_motor.h"
#include <Arduino.h>
#define IN1 25
#define IN2 26
#define ENA 27
static int _speed=0;
void motor_setup(){pinMode(IN1,OUTPUT);pinMode(IN2,OUTPUT);ledcAttach(ENA,5000,8);Serial.println("[motor] OK");}
void motor_set_speed(int s){_speed=constrain(abs(s),0,255);ledcWrite(ENA,_speed);}
void motor_forward(){digitalWrite(IN1,HIGH);digitalWrite(IN2,LOW);}
void motor_reverse(){digitalWrite(IN1,LOW);digitalWrite(IN2,HIGH);}
void motor_stop(){digitalWrite(IN1,LOW);digitalWrite(IN2,LOW);ledcWrite(ENA,0);}
